1	import { useCallback, useEffect, useMemo } from 'react';
2	import {
3	  Modal,
4	  Pressable,
5	  type StyleProp,
6	  StyleSheet,
7	  useWindowDimensions,
8	  View,
9	  type ViewStyle,
10	} from 'react-native';
11	import {
12	  Gesture,
13	  GestureDetector,
14	  GestureHandlerRootView,
15	} from 'react-native-gesture-handler';
16	import Animated, {
17	  runOnJS,
18	  useAnimatedStyle,
19	  useSharedValue,
20	  withSpring,
21	  withTiming,
22	  type WithSpringConfig,
23	} from 'react-native-reanimated';
24	import { colors, radii, shadows, spacing } from '@/design/tokens';
25	import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
26	import { useReducedMotion } from '@/design/useReducedMotion';
27	
28	// Modal bottom sheet per docs/design.md §3.3 ("Bottom sheet (80% height)") +
29	// §6 inventory (children, snapPoints). Slides up on open with SPRING_SNAPPY per
30	// §1.4 line 99. Drag-to-dismiss via react-native-gesture-handler PanGesture:
31	// snap to the nearest provided snap point, or dismiss when pulled past the
32	// lowest snap + threshold or flung downward.
33	//
34	// snapPoints are fractions of screen height. The FIRST entry is the initial
35	// (and largest) snap — sheet height is set from it. Additional smaller entries
36	// create peek positions the user can drag to.
37	const DISMISS_VELOCITY = 600; // px/s — fling-dismiss threshold
38	const DISMISS_DRAG_OVERSHOOT = 0.25; // extra drag past lowest snap before dismissing (as fraction of sheetHeight)
39	
40	export type BottomSheetProps = {
41	  visible: boolean;
42	  onDismiss: () => void;
43	  children: React.ReactNode;
44	  snapPoints?: readonly number[];
45	  style?: StyleProp<ViewStyle>;
46	  accessibilityLabel?: string;
47	  testID?: string;
48	};
49	
50	export function BottomSheet({
51	  visible,
52	  onDismiss,
53	  children,
54	  snapPoints = [0.8],
55	  style,
56	  accessibilityLabel,
57	  testID,
58	}: BottomSheetProps) {
59	  const reduced = useReducedMotion();
60	  const { height: screenHeight } = useWindowDimensions();
61	
62	  const { sheetHeight, snapOffsets } = useMemo(() => {
63	    const sorted = [...snapPoints]
64	      .map((p) => clamp(p, 0.2, 0.95))
65	      .sort((a, b) => b - a);
66	    const primary = sorted[0] ?? 0.8;
67	    const h = screenHeight * primary;
68	    // snapOffsets[0] is always 0 (fully shown at primary snap). Subsequent
69	    // entries are positive translateY offsets sliding the sheet down for peeks.
70	    const offsets = sorted.map((p) => h * (1 - p / primary));
71	    return { sheetHeight: h, snapOffsets: offsets };
72	  }, [snapPoints, screenHeight]);
73	
74	  const translateY = useSharedValue(sheetHeight);
75	  const backdropOpacity = useSharedValue(0);
76	  const gestureStart = useSharedValue(0);
77	
78	  useEffect(() => {
79	    if (visible) {
80	      translateY.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced));
81	      backdropOpacity.value = withTiming(1, { duration: reduced ? 0 : 180 });
82	    } else {
83	      translateY.value = withSpring(
84	        sheetHeight,
85	        withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
86	      );
87	      backdropOpacity.value = withTiming(0, { duration: reduced ? 0 : 160 });
88	    }
89	  }, [visible, reduced, sheetHeight, translateY, backdropOpacity]);
90	
91	  const dismissFromJS = useCallback(() => {
92	    onDismiss();
93	  }, [onDismiss]);
94	
95	  const pan = useMemo(
96	    () =>
97	      Gesture.Pan()
98	        .onStart(() => {
99	          gestureStart.value = translateY.value;
100	        })
101	        .onUpdate((e) => {
102	          translateY.value = Math.max(0, gestureStart.value + e.translationY);
103	        })
104	        .onEnd((e) => {
105	          const final = translateY.value;
106	          const largestOffset = snapOffsets[snapOffsets.length - 1] ?? 0;
107	          const shouldDismiss =
108	            final > largestOffset + sheetHeight * DISMISS_DRAG_OVERSHOOT ||
109	            e.velocityY > DISMISS_VELOCITY;
110	          if (shouldDismiss) {
111	            runOnJS(dismissFromJS)();
112	            return;
113	          }
114	          let nearest = snapOffsets[0] ?? 0;
115	          let bestDist = Math.abs(final - nearest);
116	          for (const o of snapOffsets) {
117	            const d = Math.abs(final - o);
118	            if (d < bestDist) {
119	              bestDist = d;
120	              nearest = o;
121	            }
122	          }
123	          translateY.value = withSpring(
124	            nearest,
125	            withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
126	          );
127	        }),
128	    [gestureStart, translateY, snapOffsets, sheetHeight, reduced, dismissFromJS],
129	  );
130	
131	  const sheetAnimatedStyle = useAnimatedStyle(() => ({
132	    transform: [{ translateY: translateY.value }],
133	  }));
134	
135	  const backdropAnimatedStyle = useAnimatedStyle(() => ({
136	    opacity: backdropOpacity.value * 0.45,
137	  }));
138	
139	  return (
140	    <Modal
141	      visible={visible}
142	      transparent
143	      onRequestClose={onDismiss}
144	      animationType="none"
145	      statusBarTranslucent
146	      testID={testID}
147	    >
148	      {/* New GestureHandlerRootView inside Modal — on Android, Modal opens a new
149	          window that does not inherit the root handler from app/_layout.tsx. */}
150	      <GestureHandlerRootView style={styles.root}>
151	        <Animated.View style={[styles.backdrop, backdropAnimatedStyle]}>
152	          <Pressable
153	            style={StyleSheet.absoluteFill}
154	            onPress={onDismiss}
155	            accessibilityRole="button"
156	            accessibilityLabel="Dismiss sheet"
157	          />
158	        </Animated.View>
159	        <GestureDetector gesture={pan}>
160	          <Animated.View
161	            style={[styles.sheet, { height: sheetHeight }, shadows.hard, sheetAnimatedStyle, style]}
162	            accessibilityViewIsModal
163	            accessibilityLabel={accessibilityLabel}
164	          >
165	            <View style={styles.handle} />
166	            <View style={styles.content}>{children}</View>
167	          </Animated.View>
168	        </GestureDetector>
169	      </GestureHandlerRootView>
170	    </Modal>
171	  );
172	}
173	
174	function clamp(v: number, min: number, max: number) {
175	  return Math.min(max, Math.max(min, v));
176	}
177	
178	const styles = StyleSheet.create({
179	  root: {
180	    flex: 1,
181	    justifyContent: 'flex-end',
182	  },
183	  backdrop: {
184	    ...StyleSheet.absoluteFillObject,
185	    backgroundColor: colors.ink,
186	  },
187	  sheet: {
188	    backgroundColor: colors.canvas,
189	    borderTopLeftRadius: radii.card,
190	    borderTopRightRadius: radii.card,
191	    borderWidth: 2,
192	    borderBottomWidth: 0,
193	    borderColor: colors.ink,
194	    paddingTop: spacing.sm,
195	    // Shadow on a bottom-pinned sheet reads upward.
196	    shadowOffset: { width: 0, height: -3 },
197	  },
198	  handle: {
199	    alignSelf: 'center',
200	    width: 48,
201	    height: 4,
202	    borderRadius: radii.pill,
203	    backgroundColor: colors.ink40,
204	    marginBottom: spacing.sm,
205	  },
206	  content: {
207	    flex: 1,
208	    paddingHorizontal: spacing.xl,
209	    paddingBottom: spacing.xxl + spacing.base, // covers iOS home-indicator area
210	  },
211	});
