1	import {
2	  createContext,
3	  useCallback,
4	  useContext,
5	  useEffect,
6	  useMemo,
7	  useRef,
8	  useState,
9	} from 'react';
10	import {
11	  type LayoutChangeEvent,
12	  Pressable,
13	  SafeAreaView,
14	  StyleSheet,
15	  Text,
16	  View,
17	} from 'react-native';
18	import Animated, {
19	  cancelAnimation,
20	  Easing,
21	  useAnimatedStyle,
22	  useSharedValue,
23	  withSpring,
24	  withTiming,
25	  type WithSpringConfig,
26	} from 'react-native-reanimated';
27	import { X } from 'lucide-react-native';
28	import { colors, radii, shadows, spacing } from '@/design/tokens';
29	import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
30	import { useReducedMotion } from '@/design/useReducedMotion';
31	import { textStyles } from '@/design/typography';
32	
33	// Global toast banner per docs/design.md §6 inventory (`message, variant, duration`)
34	// and §1.4 line 439 ("2.5s success toast"). Mount ToastProvider once near the root
35	// (app/_layout.tsx) and call useToast().show({...}) from anywhere.
36	//
37	// Variants drive the soft-bg + border color from the semantic palette in §1.2.
38	// Progress bar counts down the remaining duration so the user can gauge when it
39	// will auto-dismiss.
40	
41	export type ToastVariant = 'success' | 'error' | 'info';
42	
43	export type ToastPayload = {
44	  message: string;
45	  variant?: ToastVariant;
46	  duration?: number; // ms, default 2500
47	};
48	
49	type ToastContextValue = {
50	  show: (t: ToastPayload) => void;
51	  hide: () => void;
52	};
53	
54	const DEFAULT_DURATION = 2500;
55	
56	const ToastContext = createContext<ToastContextValue | null>(null);
57	
58	export function useToast(): ToastContextValue {
59	  const ctx = useContext(ToastContext);
60	  if (!ctx) {
61	    throw new Error('useToast must be used inside <ToastProvider>');
62	  }
63	  return ctx;
64	}
65	
66	type InternalToast = {
67	  id: number;
68	  message: string;
69	  variant: ToastVariant;
70	  duration: number;
71	};
72	
73	export function ToastProvider({ children }: { children: React.ReactNode }) {
74	  const [toast, setToast] = useState<InternalToast | null>(null);
75	  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
76	
77	  const clearTimer = () => {
78	    if (timerRef.current) {
79	      clearTimeout(timerRef.current);
80	      timerRef.current = null;
81	    }
82	  };
83	
84	  const hide = useCallback(() => {
85	    clearTimer();
86	    setToast(null);
87	  }, []);
88	
89	  const show = useCallback((t: ToastPayload) => {
90	    clearTimer();
91	    const id = Date.now();
92	    const duration = t.duration ?? DEFAULT_DURATION;
93	    setToast({
94	      id,
95	      message: t.message,
96	      variant: t.variant ?? 'info',
97	      duration,
98	    });
99	    timerRef.current = setTimeout(() => {
100	      timerRef.current = null;
101	      // Only clear if this toast still owns the slot (show() may have replaced it).
102	      setToast((cur) => (cur?.id === id ? null : cur));
103	    }, duration);
104	  }, []);
105	
106	  useEffect(() => () => clearTimer(), []);
107	
108	  const value = useMemo<ToastContextValue>(() => ({ show, hide }), [show, hide]);
109	
110	  return (
111	    <ToastContext.Provider value={value}>
112	      {children}
113	      {toast ? <ToastSurface toast={toast} onDismiss={hide} /> : null}
114	    </ToastContext.Provider>
115	  );
116	}
117	
118	type VariantPalette = { bg: string; border: string };
119	
120	const VARIANT_PALETTE: Record<ToastVariant, VariantPalette> = {
121	  success: { bg: colors.successSoft, border: colors.success },
122	  error: { bg: colors.dangerSoft, border: colors.danger },
123	  info: { bg: colors.primarySoft, border: colors.primary },
124	};
125	
126	type ToastSurfaceProps = {
127	  toast: InternalToast;
128	  onDismiss: () => void;
129	};
130	
131	function ToastSurface({ toast, onDismiss }: ToastSurfaceProps) {
132	  const reduced = useReducedMotion();
133	  const translateY = useSharedValue(-140);
134	  const progress = useSharedValue(1);
135	  const trackWidth = useSharedValue(0);
136	
137	  useEffect(() => {
138	    // Reset each time a new toast replaces the slot (toast.id changes) so the
139	    // enter spring + progress countdown replay from their start positions.
140	    translateY.value = -140;
141	    translateY.value = withSpring(
142	      0,
143	      withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
144	    );
145	    progress.value = 1;
146	    if (!reduced) {
147	      progress.value = withTiming(0, {
148	        duration: toast.duration,
149	        easing: Easing.linear,
150	      });
151	    }
152	    return () => {
153	      cancelAnimation(translateY);
154	      cancelAnimation(progress);
155	    };
156	  }, [toast.id, toast.duration, reduced, translateY, progress]);
157	
158	  const handleTrackLayout = (event: LayoutChangeEvent) => {
159	    trackWidth.value = event.nativeEvent.layout.width;
160	  };
161	
162	  const bannerStyle = useAnimatedStyle(() => ({
163	    transform: [{ translateY: translateY.value }],
164	  }));
165	
166	  const progressFillStyle = useAnimatedStyle(() => ({
167	    width: trackWidth.value * progress.value,
168	  }));
169	
170	  const palette = VARIANT_PALETTE[toast.variant];
171	
172	  return (
173	    <SafeAreaView pointerEvents="box-none" style={styles.root}>
174	      <Animated.View
175	        pointerEvents="auto"
176	        style={[
177	          styles.banner,
178	          { backgroundColor: palette.bg, borderColor: palette.border },
179	          shadows.hard,
180	          bannerStyle,
181	        ]}
182	        accessibilityLiveRegion="polite"
183	        accessibilityRole="alert"
184	      >
185	        <View style={styles.row}>
186	          <Text
187	            style={[textStyles.body, styles.message, { color: colors.ink }]}
188	            numberOfLines={3}
189	          >
190	            {toast.message}
191	          </Text>
192	          <Pressable
193	            onPress={onDismiss}
194	            accessibilityRole="button"
195	            accessibilityLabel="Dismiss notification"
196	            hitSlop={8}
197	          >
198	            <X size={18} color={colors.ink} strokeWidth={2.5} />
199	          </Pressable>
200	        </View>
201	        <View
202	          style={[styles.progressTrack, { backgroundColor: colors.surface }]}
203	          onLayout={handleTrackLayout}
204	        >
205	          <Animated.View
206	            style={[styles.progressFill, { backgroundColor: palette.border }, progressFillStyle]}
207	          />
208	        </View>
209	      </Animated.View>
210	    </SafeAreaView>
211	  );
212	}
213	
214	const styles = StyleSheet.create({
215	  root: {
216	    position: 'absolute',
217	    top: 0,
218	    left: 0,
219	    right: 0,
220	    alignItems: 'center',
221	    zIndex: 9999,
222	    elevation: 9999,
223	  },
224	  banner: {
225	    marginTop: spacing.sm,
226	    width: '92%',
227	    maxWidth: 520,
228	    borderRadius: radii.card,
229	    borderWidth: 2,
230	    paddingVertical: spacing.md,
231	    paddingHorizontal: spacing.base,
232	  },
233	  row: {
234	    flexDirection: 'row',
235	    alignItems: 'center',
236	    gap: spacing.sm,
237	  },
238	  message: {
239	    flex: 1,
240	  },
241	  progressTrack: {
242	    marginTop: spacing.sm,
243	    height: 3,
244	    borderRadius: radii.pill,
245	    overflow: 'hidden',
246	  },
247	  progressFill: {
248	    height: '100%',
249	    borderRadius: radii.pill,
250	  },
251	});
