1	import { useCallback } from 'react';
2	import {
3	  ActivityIndicator,
4	  Pressable,
5	  type PressableProps,
6	  type StyleProp,
7	  StyleSheet,
8	  Text,
9	  type ViewStyle,
10	} from 'react-native';
11	import Animated, {
12	  useAnimatedStyle,
13	  useSharedValue,
14	  withSpring,
15	  type WithSpringConfig,
16	} from 'react-native-reanimated';
17	import * as Haptics from 'expo-haptics';
18	import { colors, radii, shadows, spacing } from '@/design/tokens';
19	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
20	import { useReducedMotion } from '@/design/useReducedMotion';
21	import { textStyles } from '@/design/typography';
22	
23	type Variant = 'primary' | 'secondary';
24	
25	export type ButtonProps = {
26	  label: string;
27	  onPress: PressableProps['onPress'];
28	  disabled?: boolean;
29	  loading?: boolean;
30	  style?: StyleProp<ViewStyle>;
31	  accessibilityLabel?: string;
32	  testID?: string;
33	};
34	
35	// Neubrutalist press — docs/design.md §1.4 (scale 0.97 on pressIn, spring.soft),
36	// §1.5 (hard shadow (3,3) collapses on press). Reanimated can't animate the
37	// compound `shadowOffset` prop; we fade `shadowOpacity` to 0 while translating
38	// (3,3) so the shadow visually "collapses" into the button.
39	function useBaseButton(interactive: boolean) {
40	  const reduced = useReducedMotion();
41	  const pressed = useSharedValue(0);
42	
43	  const animatedStyle = useAnimatedStyle(() => {
44	    const v = pressed.value;
45	    return {
46	      transform: [
47	        { translateX: v * 3 },
48	        { translateY: v * 3 },
49	        { scale: 1 - v * 0.03 },
50	      ],
51	      shadowOpacity: 1 - v,
52	    };
53	  });
54	
55	  const handlePressIn = useCallback(() => {
56	    if (!interactive) return;
57	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
58	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
59	  }, [interactive, pressed, reduced]);
60	
61	  const handlePressOut = useCallback(() => {
62	    if (!interactive) return;
63	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
64	  }, [interactive, pressed, reduced]);
65	
66	  return { animatedStyle, handlePressIn, handlePressOut };
67	}
68	
69	function BaseButton({
70	  label,
71	  onPress,
72	  disabled = false,
73	  loading = false,
74	  variant,
75	  style,
76	  accessibilityLabel,
77	  testID,
78	}: ButtonProps & { variant: Variant }) {
79	  const interactive = !disabled && !loading;
80	  const { animatedStyle, handlePressIn, handlePressOut } = useBaseButton(interactive);
81	
82	  const variantStyle = variant === 'primary' ? styles.primary : styles.secondary;
83	  const labelColor = disabled ? colors.ink40 : colors.ink;
84	
85	  return (
86	    <Pressable
87	      onPress={interactive ? onPress : undefined}
88	      onPressIn={handlePressIn}
89	      onPressOut={handlePressOut}
90	      disabled={!interactive}
91	      accessibilityRole="button"
92	      accessibilityLabel={accessibilityLabel ?? label}
93	      accessibilityState={{ disabled: !interactive, busy: loading }}
94	      testID={testID}
95	    >
96	      <Animated.View
97	        style={[
98	          styles.base,
99	          variantStyle,
100	          disabled ? styles.disabled : shadows.hard,
101	          animatedStyle,
102	          style,
103	        ]}
104	      >
105	        {loading ? (
106	          <ActivityIndicator color={colors.ink} />
107	        ) : (
108	          <Text style={[textStyles.body, { color: labelColor }]}>{label}</Text>
109	        )}
110	      </Animated.View>
111	    </Pressable>
112	  );
113	}
114	
115	export function ButtonPrimary(props: ButtonProps) {
116	  return <BaseButton {...props} variant="primary" />;
117	}
118	
119	export function ButtonSecondary(props: ButtonProps) {
120	  return <BaseButton {...props} variant="secondary" />;
121	}
122	
123	const styles = StyleSheet.create({
124	  base: {
125	    minHeight: 48,
126	    paddingHorizontal: spacing.lg,
127	    paddingVertical: spacing.md,
128	    borderRadius: radii.button,
129	    borderWidth: 2,
130	    borderColor: colors.ink,
131	    alignItems: 'center',
132	    justifyContent: 'center',
133	    shadowColor: colors.ink,
134	    shadowOpacity: 1,
135	    shadowRadius: 0,
136	  },
137	  primary: {
138	    backgroundColor: colors.cta,
139	  },
140	  secondary: {
141	    backgroundColor: colors.surface,
142	  },
143	  disabled: {
144	    backgroundColor: colors.hairline,
145	    borderColor: colors.ink40,
146	    shadowOpacity: 0,
147	    elevation: 0,
148	  },
149	});
