1	import { useEffect } from 'react';
2	import {
3	  type LayoutChangeEvent,
4	  type StyleProp,
5	  StyleSheet,
6	  View,
7	  type ViewStyle,
8	} from 'react-native';
9	import Animated, {
10	  cancelAnimation,
11	  Easing,
12	  useAnimatedStyle,
13	  useSharedValue,
14	  withRepeat,
15	  withTiming,
16	} from 'react-native-reanimated';
17	import { colors, radii, shadows } from '@/design/tokens';
18	import { useReducedMotion } from '@/design/useReducedMotion';
19	
20	export type SkeletonCardShape = 'card' | 'line';
21	
22	export type SkeletonCardProps = {
23	  height?: number;
24	  shape?: SkeletonCardShape;
25	  style?: StyleProp<ViewStyle>;
26	  testID?: string;
27	};
28	
29	// Loading placeholder per docs/design.md §5.1 ("Loading (3 skeleton cards)") +
30	// §6 inventory. Shimmer is a translated surface-colored band animated across the
31	// skeleton's width on a repeating worklet. Reduced-motion short-circuits: the
32	// placeholder renders with its neutral hairline bg and no moving band.
33	//
34	// Width is held in a shared value (not React state) so the worklet always reads
35	// the current layout width without a re-render cycle — avoids a stale-capture
36	// flicker on the first layout pass.
37	export function SkeletonCard({
38	  height = 140,
39	  shape = 'card',
40	  style,
41	  testID,
42	}: SkeletonCardProps) {
43	  const reduced = useReducedMotion();
44	  const progress = useSharedValue(0);
45	  const width = useSharedValue(0);
46	
47	  useEffect(() => {
48	    if (reduced) return;
49	    progress.value = 0;
50	    progress.value = withRepeat(
51	      withTiming(1, { duration: 1200, easing: Easing.inOut(Easing.quad) }),
52	      -1,
53	      false,
54	    );
55	    return () => {
56	      cancelAnimation(progress);
57	    };
58	  }, [reduced, progress]);
59	
60	  const animatedStyle = useAnimatedStyle(() => {
61	    const w = width.value;
62	    if (w === 0) return { opacity: 0 };
63	    const bandWidth = Math.max(80, w * 0.4);
64	    const start = -bandWidth;
65	    const end = w;
66	    return {
67	      width: bandWidth,
68	      opacity: 1,
69	      transform: [{ translateX: start + (end - start) * progress.value }],
70	    };
71	  });
72	
73	  const handleLayout = (event: LayoutChangeEvent) => {
74	    width.value = event.nativeEvent.layout.width;
75	  };
76	
77	  const outerStyle =
78	    shape === 'card' ? [styles.card, shadows.hard, { height }] : [styles.line, { height }];
79	
80	  return (
81	    <View
82	      style={[outerStyle, style]}
83	      onLayout={handleLayout}
84	      testID={testID}
85	      accessible
86	      accessibilityLabel="Loading"
87	      accessibilityState={{ busy: true }}
88	    >
89	      {reduced ? null : (
90	        <Animated.View pointerEvents="none" style={[styles.shimmer, animatedStyle]} />
91	      )}
92	    </View>
93	  );
94	}
